class Solution {
    public int maxValue(int n, int index, int maxSum) {
        int left = 1, right = maxSum;
        while (left < right) {
            int mid = (left + right + 1) / 2;
            long sum = (long) (mid + Math.max(0, mid - index - 1)) + (long) (mid + Math.max(0, mid - (n - index - 1)));
            if (sum <= maxSum) {
                left = mid;
            } else {
                right = mid - 1;
            }
        }
        return left;
    }
}
